import{_ as t,H as i,f as a,i as o}from"./chunks/framework.Cvt1eIE0.js";const n="/store-locator/images/custome-color.png",r="/store-locator/images/map-style.png",l="/store-locator/images/custom-css.png",m=JSON.parse('{"title":"外观定制","description":"","frontmatter":{},"headers":[],"relativePath":"store-locator/guide/customization.md","filePath":"store-locator/guide/customization.md"}'),e={name:"store-locator/guide/customization.md"};function g(p,s,h,c,d,k){return i(),a("div",null,[...s[0]||(s[0]=[o('<h1 id="外观定制" tabindex="-1">外观定制 <a class="header-anchor" href="#外观定制" aria-label="Permalink to &quot;外观定制&quot;">​</a></h1><p>Jika Store Locator 提供广泛的定制选项，确保定位器完美契合您的品牌身份。</p><h2 id="布局选项-layout-options" tabindex="-1">布局选项 (Layout Options) <a class="header-anchor" href="#布局选项-layout-options" aria-label="Permalink to &quot;布局选项 (Layout Options)&quot;">​</a></h2><p>根据您选择的发布模式（Mode），您可以使用的布局引擎有所不同：</p><p><strong>Mode 1: Managed Page (自动页面)</strong> 支持以下 2 种布局：</p><ul><li><strong>Classic (经典)</strong>：传统的左侧列表、右侧地图布局。</li><li><strong>Stacked (堆叠)</strong>：地图在上，列表在下。非常适合移动端体验。</li></ul><p><strong>Mode 2: Theme Section (主题区块) &amp; Mode 3: Widget (挂件)</strong> 支持全量 9 种布局，可在主题编辑器中切换：</p><ul><li><strong>Classic (经典)</strong>：传统的左侧列表、右侧地图布局。</li><li><strong>Stacked (堆叠)</strong>：地图在上，列表在下。</li><li><strong>Floating (悬浮)</strong>：磨砂半透明质感，现代感十足。</li><li><strong>Modern (现代)</strong>：带有浮动搜索面板的全屏界面。</li><li><strong>Minimal (极简)</strong>：以搜索为中心的简洁布局，适合嵌入窄小区域。</li><li><strong>Overlay (覆盖)</strong>：侧边栏浮动在地图上，可随时折叠。</li><li><strong>Grid (网格)</strong>：地图下方以横向卡片形式展示门店。</li><li><strong>Compact (紧凑)</strong>：专门为小空间设计的气泡式 UI。</li><li><strong>Split Search (分栏搜索)</strong>：搜索框与地图并排的左右分栏布局。</li></ul><h2 id="外观设置-appearance-settings" tabindex="-1">外观设置 (Appearance Settings) <a class="header-anchor" href="#外观设置-appearance-settings" aria-label="Permalink to &quot;外观设置 (Appearance Settings)&quot;">​</a></h2><p>导航到 <strong>Settings &gt; Appearance</strong>，您可以自定义几乎所有视觉元素： <img src="'+n+'" alt="样式自定义"></p><ul><li><strong>主色调 (Primary Color)</strong>：用于按钮、激活状态。</li><li><strong>背景颜色</strong>：可分别控制应用整体背景和商店列表背景。</li><li><strong>文字与次要颜色</strong>：确保品牌调性的同时兼顾易读性。</li><li><strong>商店卡片</strong>：自定义圆角大小、垂直间距和字体大小。</li><li><strong>Marker Studio (标记设置)</strong>： <ul><li><strong>Marker Mode (标记模式)</strong>：可选择预设颜色 (Preset Colors) 或自定义十六进制颜色 (Custom Color)。</li><li><strong>Marker Size (标记尺寸)</strong>：调整大头针大小以获得最佳可见度。</li><li><strong>自定义图标</strong>：输入您自己的图片（SVG 或 PNG）URL 作为地图标记。</li></ul></li></ul><h2 id="地图主题" tabindex="-1">地图主题 <a class="header-anchor" href="#地图主题" aria-label="Permalink to &quot;地图主题&quot;">​</a></h2><p><img src="'+r+'" alt="地图样式"> 从多种预配置的地图风格中选择，适配不同的品牌氛围：</p><ul><li><strong>Default (默认)</strong>：标准 Google Maps 外观。</li><li><strong>Autumn Echo (秋日回响)</strong>：温馨的秋季色调。</li><li><strong>Dusty Rose (灰粉物语)</strong>：优雅的干枯玫瑰色。</li><li><strong>Macaron Mint (马卡龙薄荷)</strong>：清新的浅绿色。</li><li><strong>Muted Sage (暗色鼠尾草)</strong>：低饱和度的自然绿色。</li><li><strong>Nordic Night (北欧之夜)</strong>：冷调深蓝主题。</li><li><strong>Titanium Industrial (钛金工业)</strong>：硬朗的金属灰风格。</li><li><strong>Neon Ash (霓虹灰)</strong>：高对比度黑色主题。</li></ul><h2 id="自定义-css" tabindex="-1">自定义 CSS <a class="header-anchor" href="#自定义-css" aria-label="Permalink to &quot;自定义 CSS&quot;">​</a></h2><p>针对高级用户，我们提供了 <strong>Custom CSS</strong> 字段。您可以编写自己的 CSS 规则来覆盖定位器的任何样式。 以及定制专属地图样式。 <img src="'+l+`" alt="地图样式"> 示例：</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">#jika-store-finder-app</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> .jika-item</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  border</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">px</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> solid</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> #ff0000</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> !important</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div>`,17)])])}const _=t(e,[["render",g]]);export{m as __pageData,_ as default};
